import React, { useMemo, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { apiFetch } from '../utils/api';
import { getRouteConfigForPath } from '../app/routes';

type AssistantResponse = {
  intent: string;
  action: string;
  parameters: Record<string, any>;
  summary?: string;
  error?: string;
  timestamp?: string;
};

type AssistantStatusResponse = {
  status?: string;
  model_available?: boolean;
  message?: string;
};

type AssistantHistoryItem = {
  id: string;
  pageKey: string;
  question: string;
  response: AssistantResponse;
  createdAt: string;
};

const ASSISTANT_OPEN_SESSION_KEY = 'lt-assistant-open';
const ASSISTANT_HISTORY_SESSION_KEY = 'lt-assistant-history-by-page';

const readAssistantOpenState = (): boolean => {
  if (typeof window === 'undefined') {
    return false;
  }
  return window.sessionStorage.getItem(ASSISTANT_OPEN_SESSION_KEY) === '1';
};

const readAssistantHistory = (): Record<string, AssistantHistoryItem[]> => {
  if (typeof window === 'undefined') {
    return {};
  }

  const raw = window.sessionStorage.getItem(ASSISTANT_HISTORY_SESSION_KEY);
  if (!raw) {
    return {};
  }

  try {
    const parsed = JSON.parse(raw) as Record<string, AssistantHistoryItem[]>;
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch (_error) {
    return {};
  }
};

const AssistantPanel: React.FC = () => {
  const location = useLocation();
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [isOpen, setIsOpen] = useState<boolean>(readAssistantOpenState);
  const [statusMessage, setStatusMessage] = useState<string>('Model status wordt gecontroleerd...');
  const [modelAvailable, setModelAvailable] = useState<boolean>(false);
  const [historyByPage, setHistoryByPage] = useState<Record<string, AssistantHistoryItem[]>>(readAssistantHistory);

  React.useEffect(() => {
    let isMounted = true;

    const loadStatus = async () => {
      try {
        const status = await apiFetch<AssistantStatusResponse>('/api/assistant/status');
        if (!isMounted) {
          return;
        }
        const isAvailable = typeof status.model_available === 'boolean'
          ? status.model_available
          : status.status === 'ok';
        setModelAvailable(Boolean(isAvailable));
        setStatusMessage(status.message || (status.model_available ? 'Model beschikbaar' : 'Model niet beschikbaar'));
      } catch (_error) {
        if (!isMounted) {
          return;
        }
        setModelAvailable(false);
        setStatusMessage('Assistent status niet bereikbaar');
      }
    };

    void loadStatus();
    const intervalId = window.setInterval(() => {
      void loadStatus();
    }, 30000);

    return () => {
      isMounted = false;
      window.clearInterval(intervalId);
    };
  }, []);

  React.useEffect(() => {
    const handleOpenRequest = () => {
      if (modelAvailable) {
        setIsOpen(true);
      }
    };

    window.addEventListener('lt-assistant-open', handleOpenRequest);
    return () => {
      window.removeEventListener('lt-assistant-open', handleOpenRequest);
    };
  }, [modelAvailable]);

  React.useEffect(() => {
    if (typeof window === 'undefined') {
      return;
    }
    window.sessionStorage.setItem(ASSISTANT_OPEN_SESSION_KEY, isOpen ? '1' : '0');
  }, [isOpen]);

  React.useEffect(() => {
    if (!isOpen) {
      return;
    }

    const onEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        setIsOpen(false);
      }
    };

    window.addEventListener('keydown', onEscape);
    return () => {
      window.removeEventListener('keydown', onEscape);
    };
  }, [isOpen]);

  const routeConfig = useMemo(() => getRouteConfigForPath(location.pathname), [location.pathname]);
  const pageKey = useMemo(() => `${location.pathname}${location.search}`, [location.pathname, location.search]);
  const pageHistory = useMemo(() => historyByPage[pageKey] ?? [], [historyByPage, pageKey]);

  const contextualizedPrompt = useMemo(() => {
    const pageContext = [
      `Route label: ${routeConfig.label}`,
      `Path: ${location.pathname}`,
      `Search: ${location.search || '(none)'}`,
      `Section: ${routeConfig.section}`,
      `Context title: ${routeConfig.context.title}`,
      `Context subtitle: ${routeConfig.context.subtitle}`,
    ].join('\n');

    return `[PAGE CONTEXT]\n${pageContext}\n\n[USER QUESTION]\n${prompt.trim()}`;
  }, [location.pathname, location.search, prompt, routeConfig]);

  const handleAsk = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || !modelAvailable) {
      return;
    }

    const questionText = prompt.trim();
    setLoading(true);

    try {
      const result = await apiFetch<AssistantResponse>('/api/assistant/ask', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          query: contextualizedPrompt,
        }),
      });

      const historyItem: AssistantHistoryItem = {
        id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        pageKey,
        question: questionText,
        response: result,
        createdAt: new Date().toISOString(),
      };

      setHistoryByPage((prev) => {
        const next = {
          ...prev,
          [pageKey]: [...(prev[pageKey] ?? []), historyItem].slice(-25),
        };
        if (typeof window !== 'undefined') {
          window.sessionStorage.setItem(ASSISTANT_HISTORY_SESSION_KEY, JSON.stringify(next));
        }
        return next;
      });
      setPrompt('');
    } catch (e: any) {
      const errorResult: AssistantResponse = {
        intent: 'error',
        action: 'error',
        parameters: {},
        error: e.message,
      };

      const historyItem: AssistantHistoryItem = {
        id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        pageKey,
        question: questionText,
        response: errorResult,
        createdAt: new Date().toISOString(),
      };

      setHistoryByPage((prev) => {
        const next = {
          ...prev,
          [pageKey]: [...(prev[pageKey] ?? []), historyItem].slice(-25),
        };
        if (typeof window !== 'undefined') {
          window.sessionStorage.setItem(ASSISTANT_HISTORY_SESSION_KEY, JSON.stringify(next));
        }
        return next;
      });
    } finally {
      setLoading(false);
    }
  };

  const getIntentToneClass = (intent: string) => {
    const classes: Record<string, string> = {
      search: 'border-l-sky-500',
      add: 'border-l-emerald-500',
      edit: 'border-l-amber-500',
      delete: 'border-l-rose-500',
      show: 'border-l-violet-500',
      stats: 'border-l-cyan-500',
      info: 'border-l-slate-500',
      error: 'border-l-rose-600',
    };
    return classes[intent] || 'border-l-slate-400';
  };

  const getIntentTextClass = (intent: string) => {
    const classes: Record<string, string> = {
      search: 'text-sky-600',
      add: 'text-emerald-600',
      edit: 'text-amber-600',
      delete: 'text-rose-600',
      show: 'text-violet-600',
      stats: 'text-cyan-600',
      info: 'text-slate-600',
      error: 'text-rose-700',
    };
    return classes[intent] || 'text-slate-600';
  };

  const fieldControlClass =
    'w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-800 shadow-sm transition placeholder:text-slate-400 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-lt-primary disabled:cursor-not-allowed disabled:opacity-60';
  const primaryButtonClass =
    'inline-flex items-center justify-center rounded-md border border-lt-primary bg-lt-primary px-4 py-2 text-sm font-medium text-white shadow-sm transition hover:bg-blue-700 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-lt-primary disabled:cursor-not-allowed disabled:opacity-50';
  const iconButtonClass =
    'fixed bottom-6 right-6 z-[120] inline-flex h-14 w-14 items-center justify-center rounded-full border shadow-lg transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-lt-primary';
  const popupClass =
    'fixed bottom-24 right-6 z-[130] w-[calc(100vw-2rem)] max-w-[30rem] rounded-xl border border-lt-border bg-lt-card p-4 shadow-2xl';

  const launchTitle = modelAvailable
    ? 'Open assistent'
    : `Assistent niet beschikbaar: ${statusMessage}`;

  const openAssistant = () => {
    if (!modelAvailable) {
      return;
    }
    setIsOpen(true);
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-[120] group">
        <button
          type="button"
          onClick={openAssistant}
          disabled={!modelAvailable}
          aria-label={modelAvailable ? 'Open assistent' : 'Assistent niet beschikbaar'}
          className={`${iconButtonClass} relative bottom-0 right-0 ${modelAvailable ? 'border-lt-primary bg-lt-primary text-white hover:bg-blue-700' : 'cursor-not-allowed border-slate-300 bg-slate-200 text-slate-500'}`}
        >
          <svg
            className="h-6 w-6"
            viewBox="0 0 24 24"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
          >
            <path
              d="M7 9h10M7 13h7m-8 8 2.3-3.1a2 2 0 0 1 1.6-.8H17a3 3 0 0 0 3-3V7a3 3 0 0 0-3-3H7a3 3 0 0 0-3 3v7a3 3 0 0 0 3 3h.1"
              stroke="currentColor"
              strokeWidth="1.8"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>
        <div className="pointer-events-none absolute bottom-16 right-0 w-72 translate-y-1 rounded-md border border-slate-300 bg-white px-3 py-2 text-xs text-slate-700 opacity-0 shadow-md transition group-hover:translate-y-0 group-hover:opacity-100 group-focus-within:translate-y-0 group-focus-within:opacity-100">
          {launchTitle}
        </div>
      </div>

      {isOpen ? (
        <div className="fixed inset-0 z-[125]" onClick={() => setIsOpen(false)} aria-hidden="true">
          <div className="absolute inset-0 bg-slate-900/35" />
        </div>
      ) : null}

      {isOpen ? (
        <section className={popupClass} role="dialog" aria-modal="true" aria-label="Assistent popup">
          <div className="mb-3 flex items-start justify-between gap-3">
            <div>
              <h3 className="text-base font-semibold text-lt-heading">Assistent</h3>
              <p className="mt-1 text-xs text-lt-muted">Context: {routeConfig.label} ({location.pathname})</p>
            </div>
            <button
              type="button"
              className="rounded-md border border-slate-300 px-2 py-1 text-xs font-medium text-slate-700 hover:bg-slate-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-lt-primary"
              onClick={() => setIsOpen(false)}
            >
              Sluit
            </button>
          </div>

          <form onSubmit={handleAsk} className="grid gap-3">
            <textarea
              placeholder="Stel een vraag over deze pagina of data..."
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              rows={4}
              className={fieldControlClass}
            />

            <div className="flex items-center justify-between gap-3">
              <p className="text-xs text-lt-muted">{statusMessage}</p>
              <button
                type="submit"
                disabled={loading || !prompt.trim() || !modelAvailable}
                className={primaryButtonClass}
              >
                {loading ? 'Verwerking...' : 'Vraag'}
              </button>
            </div>
          </form>

          {pageHistory.length > 0 ? (
            <div className="mt-3 max-h-64 space-y-3 overflow-auto pr-1">
              {pageHistory.map((item) => (
                <article key={item.id} className="rounded-md border border-lt-border bg-white p-3">
                  <div className="mb-2 text-[11px] font-semibold uppercase tracking-wide text-lt-muted">Vraag</div>
                  <p className="mb-3 whitespace-pre-wrap text-sm text-lt-text">{item.question}</p>

                  <div className="mb-1 text-[11px] font-semibold uppercase tracking-wide text-lt-muted">
                    Intent: <span className={`${getIntentTextClass(item.response.intent)} uppercase`}>{item.response.intent}</span>
                  </div>

                  {item.response.action ? (
                    <div className="mb-2 text-xs text-lt-muted">Action: {item.response.action}</div>
                  ) : null}

                  <div className={`rounded-md border border-l-4 border-lt-border p-2 ${getIntentToneClass(item.response.intent)} ${item.response.intent === 'error' ? 'bg-rose-50' : 'bg-slate-50'}`}>
                    {item.response.summary ? (
                      <div className="whitespace-pre-wrap text-sm text-lt-text">{item.response.summary}</div>
                    ) : null}

                    {Object.keys(item.response.parameters || {}).length > 0 ? (
                      <pre className="mt-2 max-h-32 overflow-auto rounded-md bg-white p-2 text-xs text-slate-700">
                        {JSON.stringify(item.response.parameters, null, 2)}
                      </pre>
                    ) : null}

                    {item.response.error ? (
                      <div className="mt-2 rounded-md bg-rose-50 p-2 text-xs text-rose-700">{item.response.error}</div>
                    ) : null}
                  </div>

                  <div className="mt-2 text-[11px] text-lt-muted">
                    {new Date(item.createdAt).toLocaleTimeString('nl-NL')}
                  </div>
                </article>
              ))}
            </div>
          ) : (
            <div className="mt-3 rounded-md border border-dashed border-slate-300 bg-slate-50 p-3 text-xs text-lt-muted">
              Nog geen gesprek op deze pagina.
            </div>
          )}
        </section>
      ) : null}
    </>
  );
};

export default AssistantPanel;
